mapper.select:
SELECT COALESCE(MAX(version_no), 0)
FROM user_spec_version
WHERE user_id = #{userId}

SELECT password
FROM users
WHERE id = #{userId}

SELECT COUNT(*)
FROM user_certificate
WHERE spec_version_id = #{specVersionId}
  AND cert_id         = #{certId}
  AND status          = #{status}

  AND acquired_at = #{acquiredAt}

SELECT COUNT(*)
FROM user_language_score
WHERE spec_version_id = #{specVersionId}
  AND lang_type       = #{langType}
